export default class WebviewScreen extends Component {
    render() {
        return (
            <WebView
                originWhitelist={['*']}
                source={{ uri: 'https://mobile-demo.herokuapp.com/' }}
                onMessage={(event) => this._onMessage(event)} // message from WebView
            />
        );
    }

    _onMessage = (event) => {
        let msg;

        try{
          msg = JSON.parse(event.nativeEvent.data);

          // get access to navigator object in JS
          const navObj = msg.object.navigator;
        } catch(e){
          console.log("Could not parse JSON string");
          return false;
        }

        // send message back to iOS
        this.props.navigation.dispatch({
            type: 'MessageToBridge', 

            // pass some custom data with our messages as a payload
            payload: {
                text: msg,

                // if you want to send an object - use JSON stringfication/parsing
                json_object: {},
            },
        });
    }
}